DECLARE ins_count INTEGER;
SET ins_count = 0;
WHILE (DB.DBA.DICT_SIZE(dict_var) > 0) DO
  SET triples = dict_destructive_list_rnd_keys(dict_var, 80000);
  SET ins_count = ins_count + DB.DBA.RDF_INSERT_TRIPLES('http://example.com/graph', triples, 1);
END WHILE;
RETURN sprintf('Inserted %d triples', ins_count);
